func newAuthCmd(flags *rootFlags) *cobra.Command {
	cmd := &cobra.Command{
		Use:   "auth",
		Short: "Manage SALESFORCE_ACCESS_TOKEN credentials",
	}

	cmd.AddCommand(newAuthLoginCmd(flags))
	cmd.AddCommand(newAuthStatusCmd(flags))
	cmd.AddCommand(newAuthLogoutCmd(flags))
	cmd.AddCommand(newAuthSwitchOrgCmd(flags))
	cmd.AddCommand(newAuthListOrgsCmd(flags))

	return cmd
}

func newAuthLoginCmd(flags *rootFlags) *cobra.Command {
	var clientID string
	var clientSecret string
	var port int
	var sfAlias string
	var jwt bool
	var web bool
	var orgAlias string

	cmd := &cobra.Command{
		Use:   "login",
		Short: "Authenticate via sf, JWT, or OAuth2 web flow",
		RunE: func(cmd *cobra.Command, args []string) error {
			selected := 0
			for _, enabled := range []bool{sfAlias != "", jwt, web} {
				if enabled {
					selected++
				}
			}
			if selected == 0 {
				web = true
			}
			if selected > 1 {
				return fmt.Errorf("choose only one auth mode: --sf, --jwt, or --web")
			}

			ctx := cmd.Context()
			var (
				result *authpkg.Result
				alias  string
				err    error
			)
			switch {
			case sfAlias != "":
				alias = sfAlias
				result, err = authpkg.LoginSF(ctx, sfAlias, authpkg.SFOptions{})
			case jwt:
				alias = firstNonEmpty(orgAlias, ResolveOrgAlias(""), "default")
				result, err = authpkg.LoginJWT(ctx, authpkg.JWTOptions{TokenURL: tokenURLFromEnv()})
			default:
				if clientID == "" {
					return fmt.Errorf("--client-id is required")
				}
				alias = firstNonEmpty(orgAlias, ResolveOrgAlias(""), "default")
				fmt.Fprintf(os.Stderr, "Opening browser for authentication...\n")
				result, err = authpkg.LoginOAuthWeb(ctx, authpkg.OAuthOptions{
					ClientID:     clientID,
					ClientSecret: clientSecret,
					AuthURL:      authURLFromEnv(),
					TokenURL:     tokenURLFromEnv(),
					Loopback: authpkg.LoopbackOptions{
						Timeout: 2 * time.Minute,
						Listen:  fixedPortListener(port),
					},
					OpenBrowser: func(target string) error {
						fmt.Fprintf(os.Stderr, "If the browser doesn't open, visit:\n%s\n\n", target)
						return authpkg.OpenBrowser(target)
					},
				})
			}
			if err != nil {
				return err
			}
			ref := authpkg.TokenRef{Service: "salesforce-headless-360-pp-cli", Key: alias}
			expiresAt := time.Time{}
			if result.ExpiresIn > 0 {
				expiresAt = time.Now().UTC().Add(time.Duration(result.ExpiresIn) * time.Second)
			}
			if err := authpkg.StoreToken(ref, authpkg.StoredToken{
				AccessToken:  result.AccessToken,
				RefreshToken: result.RefreshToken,
				InstanceURL:  result.InstanceURL,
				Scope:        result.Scope,
				TokenType:    result.TokenType,
				ExpiresAt:    expiresAt,
			}); err != nil {
				return fmt.Errorf("saving token reference: %w", err)
			}
			values := map[string]string{"org": alias}
			if result.InstanceURL != "" {
				values["instance-url"] = result.InstanceURL
			}
			if _, err := SaveAuthProfile(alias, result.AuthMethod, ref, values); err != nil {
				return err
			}
			if err := SetActiveProfile(alias); err != nil {
				return err
			}
			if expiresAt.IsZero() {
				fmt.Fprintf(os.Stderr, "%s Authentication successful for %s via %s\n", green("OK"), alias, result.AuthMethod)
			} else {
				fmt.Fprintf(os.Stderr, "%s Authentication successful for %s via %s. Token expires at %s\n", green("OK"), alias, result.AuthMethod, expiresAt.Format(time.RFC3339))
			}
			return nil
		},
	}

	cmd.Flags().StringVar(&clientID, "client-id", os.Getenv("SALESFORCE-HEADLESS-360_CLIENT_ID"), "OAuth2 client ID")
	cmd.Flags().StringVar(&clientSecret, "client-secret", os.Getenv("SALESFORCE-HEADLESS-360_CLIENT_SECRET"), "OAuth2 client secret")
	cmd.Flags().IntVar(&port, "port", 0, "Local callback server port (0 for ephemeral)")
	cmd.Flags().StringVar(&sfAlias, "sf", "", "Use Salesforce CLI credentials for alias")
	cmd.Flags().BoolVar(&jwt, "jwt", false, "Use Salesforce JWT bearer flow")
	cmd.Flags().BoolVar(&web, "web", false, "Use OAuth2 web server flow with PKCE")
	cmd.Flags().StringVar(&orgAlias, "org", "", "Org alias for stored profile (JWT/web)")

	return cmd
}

func newAuthStatusCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:   "status",
		Short: "Show authentication status",
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return err
			}
			active := ResolveOrgAlias("")
			var activeProfile *Profile
			if active != "" {
				activeProfile, _ = GetProfile(active)
				if activeProfile != nil && cfg.AccessToken == "" && activeProfile.TokenRef.Service != "" && activeProfile.TokenRef.Key != "" {
					token, err := authpkg.LoadStoredToken(activeProfile.TokenRef)
					if err == nil {
						cfg.AccessToken = token.AccessToken
						cfg.RefreshToken = token.RefreshToken
						cfg.TokenExpiry = token.ExpiresAt
						cfg.AuthSource = "profile:" + active
					}
				}
			}

			w := cmd.OutOrStdout()
			if cfg.AccessToken == "" {
				fmt.Fprintf(w, "  %s Not authenticated. Run 'auth login' to authenticate.\n", red("FAIL"))
				return nil
			}

			if cfg.TokenExpiry.IsZero() {
				fmt.Fprintf(w, "  %s Authenticated (no expiry info)\n", green("OK"))
			} else if time.Now().Before(cfg.TokenExpiry) {
				fmt.Fprintf(w, "  %s Authenticated (expires %s)\n", green("OK"), cfg.TokenExpiry.Format(time.RFC3339))
			} else {
				if cfg.RefreshToken != "" {
					fmt.Fprintf(w, "  %s Token expired (will auto-refresh on next request)\n", yellow("WARN"))
				} else {
					fmt.Fprintf(w, "  %s Token expired. Run 'auth login' to re-authenticate.\n", red("FAIL"))
				}
			}

			if cfg.AuthSource != "" {
				fmt.Fprintf(w, "  source: %s\n", cfg.AuthSource)
			}
			if activeProfile != nil && activeProfile.AuthMethod != "" {
				fmt.Fprintf(w, "  authMethod: %s\n", activeProfile.AuthMethod)
			}
			return nil
		},
	}
}

func newAuthLogoutCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:   "logout [alias]",
		Short: "Remove stored authentication tokens",
		Args:  cobra.MaximumNArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			alias := ""
			if len(args) > 0 {
				alias = args[0]
			}
			if alias == "" {
				alias = ResolveOrgAlias("")
			}
			if alias != "" {
				if err := DeleteAuthProfile(alias); err != nil {
					return err
				}
				fmt.Fprintf(os.Stderr, "Logged out %s. Tokens removed.\n", alias)
				return nil
			}
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return err
			}
			if err := cfg.ClearTokens(); err != nil {
				return fmt.Errorf("clearing tokens: %w", err)
			}
			fmt.Fprintf(os.Stderr, "Logged out. Tokens removed.\n")
			return nil
		},
	}
}

func newAuthSwitchOrgCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:   "switch-org <alias>",
		Short: "Set the active Salesforce auth profile",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			profile, err := GetProfile(args[0])
			if err != nil {
				return err
			}
			if profile == nil {
				return fmt.Errorf("profile %q not found", args[0])
			}
			if err := SetActiveProfile(args[0]); err != nil {
				return err
			}
			fmt.Fprintf(cmd.OutOrStdout(), "active org: %s\n", args[0])
			return nil
		},
	}
}

func newAuthListOrgsCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:   "list-orgs",
		Short: "List stored Salesforce auth profiles",
		RunE: func(cmd *cobra.Command, args []string) error {
			store, err := loadProfileStore()
			if err != nil {
				return err
			}
			active, _ := ActiveProfile()
			names := make([]string, 0, len(store.Profiles))
			for name := range store.Profiles {
				names = append(names, name)
			}
			sort.Strings(names)
			if flags.asJSON {
				out := make([]map[string]any, 0, len(names))
				for _, name := range names {
					p := store.Profiles[name]
					out = append(out, map[string]any{
						"alias":       name,
						"active":      name == active,
						"authMethod":  p.AuthMethod,
						"createdAt":   p.CreatedAt,
						"lastUsedAt":  p.LastUsedAt,
						"hasTokenRef": p.TokenRef.Service != "" && p.TokenRef.Key != "",
					})
				}
				return flags.printJSON(cmd, out)
			}
			rows := make([][]string, 0, len(names))
			for _, name := range names {
				p := store.Profiles[name]
				marker := ""
				if name == active {
					marker = "*"
				}
				rows = append(rows, []string{marker, name, p.AuthMethod, p.LastUsedAt.Format(time.RFC3339)})
			}
			return flags.printTable(cmd, []string{"ACTIVE", "ALIAS", "AUTH_METHOD", "LAST_USED_AT"}, rows)
		},
	}
}

func authURLFromEnv() string {
	base := strings.TrimRight(os.Getenv("SALESFORCE_HEADLESS_360_BASE_URL"), "/")
	if base == "" {
		return "https://login.salesforce.com/services/oauth2/authorize"
	}
	return base + "/services/oauth2/authorize"
}

func tokenURLFromEnv() string {
	base := strings.TrimRight(os.Getenv("SALESFORCE_HEADLESS_360_BASE_URL"), "/")
	if base == "" {
		return "https://login.salesforce.com/services/oauth2/token"
	}
	return base + "/services/oauth2/token"
}

func fixedPortListener(port int) authpkg.ListenFunc {
	if port == 0 {
		return nil
	}
	return func(network, address string) (net.Listener, error) {
		return net.Listen(network, fmt.Sprintf("127.0.0.1:%d", port))
	}
}
